const enabled = $env.N8N_WORKFLOW_PROVIDER_HEALTH_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, reason: 'kill_switch_disabled' } }];
}
const requestId = 'ops-provider-health-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = 'n8n-provider-health-' + new Date().toISOString().slice(0, 16);
const crypto = require('crypto');
const payloadHash = crypto.createHash('sha256').update(JSON.stringify({ action: 'ops.provider_health_check', ts: new Date().toISOString().slice(0, 16) })).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'ops.provider_health_check' + payloadHash).digest('hex');
return [{ json: { killed: false, requestId, correlationId, idempotencyKey, timestamp: new Date().toISOString() } }];

const flatInput = $input.all().map((item) => item.json);
const flat = Array.isArray(flatInput[0]) ? flatInput[0] : flatInput;
const first = flat[0] || {};
const monitored = ($env.ASPIRE_PROVIDER_MONITOR_LIST || 'openai,twilio,livekit,deepgram,elevenlabs,pandadoc,stripe,supabase').split(',').map((value) => value.trim().toLowerCase()).filter(Boolean);
const invalidSource = Boolean(first && typeof first.data === 'string' && first.data.trim().startsWith('<!DOCTYPE html'));
const providersMap = new Map();
for (const name of monitored) {
  providersMap.set(name, { provider: name, totalCalls: 0, failedCalls: 0, avgLatencyMs: 0, healthStatus: 'no_data', lastSeen: null });
}
const rows = flat.filter((row) => row && typeof row === 'object' && !Array.isArray(row) && (row.external_provider || row.provider));
for (const row of rows) {
  const name = String(row.external_provider || row.provider || 'unknown').trim().toLowerCase();
  if (!providersMap.has(name)) {
    providersMap.set(name, { provider: name, totalCalls: 0, failedCalls: 0, avgLatencyMs: 0, healthStatus: 'no_data', lastSeen: null });
  }
  const entry = providersMap.get(name);
  entry.totalCalls += 1;
  const status = String(row.status || '').toLowerCase();
  if (['failed', 'partial', 'canceled', 'timeout'].includes(status)) {
    entry.failedCalls += 1;
  }
  const started = Date.parse(row.started_at || '');
  const completed = Date.parse(row.completed_at || '');
  if (Number.isFinite(started) && Number.isFinite(completed) && completed >= started) {
    const sampleCount = entry.totalCalls;
    const latency = completed - started;
    entry.avgLatencyMs = Math.round(((entry.avgLatencyMs * (sampleCount - 1)) + latency) / sampleCount);
  }
  entry.lastSeen = row.started_at || row.created_at || entry.lastSeen;
}
const providers = Array.from(providersMap.values()).map((entry) => {
  if (entry.totalCalls === 0) {
    entry.healthStatus = 'no_data';
    entry.errorRate = 0;
    return entry;
  }
  entry.errorRate = Math.round((entry.failedCalls / entry.totalCalls) * 10000) / 100;
  if (entry.errorRate >= 50) {
    entry.healthStatus = 'disconnected';
  } else if (entry.errorRate > 0) {
    entry.healthStatus = 'degraded';
  } else {
    entry.healthStatus = 'connected';
  }
  return entry;
});
let overallStatus = 'passed';
let summary = '';
if (invalidSource) {
  overallStatus = 'failed';
  summary = 'Provider health endpoint returned non-JSON content';
} else if (providers.some((entry) => entry.healthStatus === 'disconnected')) {
  overallStatus = 'failed';
  summary = `Disconnected providers detected (${providers.filter((entry) => entry.healthStatus === 'disconnected').map((entry) => entry.provider).join(', ')})`;
} else if (providers.some((entry) => entry.healthStatus === 'degraded' || entry.healthStatus === 'no_data')) {
  overallStatus = 'partial';
  summary = `Provider health degraded or missing data (${providers.filter((entry) => entry.healthStatus !== 'connected').map((entry) => `${entry.provider}:${entry.healthStatus}`).join(', ')})`;
} else {
  summary = `All monitored providers healthy (${providers.length} providers)`;
}
return [{ json: { overallStatus, summary, providers, invalidSource } }];

const crypto = require('crypto');
const prep = $('Kill Switch + Prep').item.json;
const payload = {
  id: prep.requestId,
  env: $env.ASPIRE_ROBOT_ENV || 'production',
  suite: $env.ASPIRE_ROBOT_SUITE || 'aspire_robots',
  status: $json.overallStatus || 'partial',
  startedAt: prep.timestamp || new Date().toISOString(),
  finishedAt: new Date().toISOString(),
  versionRef: ($env.ASPIRE_ROBOT_VERSION_REF || 'n8n-live') + ':provider-health',
  summary: $json.summary || 'Provider health workflow completed',
  scenarios: [{
    name: 'provider_health',
    status: $json.overallStatus || 'partial',
    summary: $json.summary || 'Provider health workflow completed',
    evidence: [
      `correlation:${prep.correlationId}`,
      `providers:${($json.providers || []).length}`,
      `invalid_source:${Boolean($json.invalidSource)}`
    ]
  }],
  meta: { workflow: 'provider-health', correlationId: prep.correlationId, requestId: prep.requestId, invalidSource: Boolean($json.invalidSource), providers: $json.providers || [] }
};
const robotBody = JSON.stringify(payload);
const robotSignature = crypto.createHmac('sha256', $env.ASPIRE_ROBOT_S2S_SECRET).update(robotBody).digest('hex');
return [{ json: { ...$json, robotBody, robotSignature } }];

const crypto = require('crypto');
const payload = {
  id: 'n8n-provider-health-error-' + Date.now(),
  env: $env.ASPIRE_ROBOT_ENV || 'production',
  suite: $env.ASPIRE_ROBOT_SUITE || 'aspire_robots',
  status: 'failed',
  startedAt: new Date().toISOString(),
  finishedAt: new Date().toISOString(),
  versionRef: ($env.ASPIRE_ROBOT_VERSION_REF || 'n8n-live') + ':provider-health',
  summary: $json.message || 'Provider health workflow failed',
  scenarios: [{ name: 'provider_health', status: 'failed', summary: $json.message || 'Provider health workflow failed', evidence: [($json.message || 'workflow_error')] }],
  meta: { workflow: 'provider-health', error: $json.message || 'Provider health workflow failed' }
};
const robotBody = JSON.stringify(payload);
const robotSignature = crypto.createHmac('sha256', $env.ASPIRE_ROBOT_S2S_SECRET).update(robotBody).digest('hex');
return [{ json: { ...$json, robotBody, robotSignature } }];
